import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import api from '../services/api';

const Signup = () => {
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [showError, setShowError] = useState(false);
  const [errorMessage, setErrorMessage] = useState('');
  const [loading, setLoading] = useState(false);
  const [termsAccepted, setTermsAccepted] = useState(false);
  const [passwordStrength, setPasswordStrength] = useState('');

  const checkPasswordStrength = (pwd) => {
    if (pwd.length < 6) return 'weak';
    if (/[A-Z]/.test(pwd) && /[0-9]/.test(pwd) && pwd.length >= 8) return 'strong';
    return 'medium';
  };

  const handlePasswordChange = (e) => {
    const pwd = e.target.value;
    setPassword(pwd);
    setPasswordStrength(checkPasswordStrength(pwd));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setShowError(false);
    setErrorMessage('');
    setLoading(true);
    if (password !== confirmPassword) {
      setShowError(true);
      setErrorMessage('Passwords do not match');
      setLoading(false);
      return;
    }
    if (!termsAccepted) {
      setShowError(true);
      setErrorMessage('You must accept the Terms of Service');
      setLoading(false);
      return;
    }
    try {
      const response = await api.post('/auth/signup', { email: email.trim(), password });
      if (response.status === 201) {
        navigate('/login', { replace: true });
      } else {
        setShowError(true);
        setErrorMessage('Signup failed. Try again.');
      }
    } catch (err) {
      setShowError(true);
      setErrorMessage(err.response?.data || 'Signup failed. Email may already exist.');
      console.error('Signup error:', err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="g-auth-bg">
      <div className="g-auth-card">
        <div className="g-auth-logo">
          <span className="g-dot g-blue"></span>
          <span className="g-dot g-red"></span>
          <span className="g-dot g-yellow"></span>
          <span className="g-dot g-green"></span>
          <h2 className="g-brand">NeuroFleetX</h2>
        </div>
        <h1 className="g-title">Sign up</h1>
        <p className="g-subtitle">Create a new account</p>
        {showError && <div className="g-error">{errorMessage}</div>}
        <form onSubmit={handleSubmit} className="g-form">
          <div className="g-field">
            <input
              type="email"
              className="g-input"
              placeholder="Email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              autoComplete="username"
              required
            />
          </div>
          <div className="g-field relative">
            <input
              type="password"
              className="g-input"
              placeholder="Password"
              value={password}
              onChange={handlePasswordChange}
              autoComplete="new-password"
              required
            />
            {password && (
              <div className={`g-password-strength ${passwordStrength}`}>
                Strength: {passwordStrength}
              </div>
            )}
          </div>
          <div className="g-field">
            <input
              type="password"
              className="g-input"
              placeholder="Confirm Password"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              autoComplete="new-password"
              required
            />
          </div>
          <div className="g-field flex items-center">
            <input
              type="checkbox"
              id="terms"
              checked={termsAccepted}
              onChange={(e) => setTermsAccepted(e.target.checked)}
              className="mr-2"
            />
            <label htmlFor="terms" className="text-sm text-gray-600">
              I accept the <a href="/terms" className="text-blue-500 hover:underline">Terms of Service</a>
            </label>
          </div>
          <div className="g-actions">
            <button type="submit" className="g-btn" disabled={loading || !termsAccepted}>
              {loading ? 'Signing up…' : 'Sign up'}
            </button>
          </div>
        </form>
        <div className="g-help">
          <Link to="/login">Already have an account?</Link>
          <span> • </span>
          <Link to="/forgot-password">Forgot password?</Link>
        </div>
      </div>
    </div>
  );
};

export default Signup;
